    .map(i => String(i.json.transaction_id || '').trim())
    .filter(Boolean)
);

const productQtyUpdates = new Map();
const now = new Date().toISOString();
const batchMap = new Map(originalBatches.map(b => [String(b.batch_id), { ...b }]));
const transactionLogs = [];
const warnings = [];
const productChangeSuggestions = [];
const cutoverDate = new Date(config.inventory_cutover_datetime || '2026-05-02T10:00:00.000Z');
const warningDays = Number(config.mhd_warning_days ?? 14);

function clean(value) {
  return String(value ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

const workflowStateRows = $items('Google Sheets - letzter Verkaufsworkflow lesen').map(i => i.json);

const workflowState = workflowStateRows.find(r =>
  clean(r.workflow_key) === 'WF3_NAYAX_FIFO'
);

const lastSuccessfulSaleDate = new Date(
  clean(workflowState?.last_inventory_review_at) ||
  config.inventory_cutover_datetime ||
  '1970-01-01T00:00:00.000Z'
);

let maxProcessedSaleDate = lastSuccessfulSaleDate;

function firstNonEmpty(...values) {
  return values.map(clean).find(value => value !== '') || '';
}

function normalizeName(value) {
  return clean(value).toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function generateProductKey(name) {
  const base = clean(name).toUpperCase()
    .replace(/Ä/g, 'AE')
    .replace(/Ö/g, 'OE')
    .replace(/Ü/g, 'UE')
    .replace(/ẞ/g, 'SS')
    .replace(/ß/g, 'SS')
    .replace(/&/g, 'UND')
    .replace(/\+/g, 'PLUS')
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return `SKU_${base || 'UNBEKANNT'}`;
}

function parseProductName(raw) {
  const text = clean(raw);
  const match = text.match(/^(.*?)\s*\((\d+)\s*=\s*([0-9]+(?:[.,][0-9]+)?)\s*\)/);
  return {
    raw,
    label: match ? clean(match[1]) : text,
    mdb_code: match ? String(match[2]) : '',
    price: match ? String(match[3]).replace(',', '.') : ''
  };
}

function saleDate(sale) {
  return new Date(
    sale.SettlementDateTimeGMT ||
    sale.MachineAuthorizationTime ||
    sale.AuthorizationDateTimeGMT ||
    0
  );
}

function saleDatetime(sale) {
  return clean(
    sale.SettlementDateTimeGMT ||
    sale.MachineAuthorizationTime ||
    sale.AuthorizationDateTimeGMT ||
    ''
  );
}

function isActiveProduct(p) {
  return clean(p.active).toUpperCase() === 'TRUE' &&
    !clean(p.valid_to) &&
    !clean(p.valid_to_datetime);
}

function namesMatch(a, b) {
  const aa = normalizeName(a);
  const bb = normalizeName(b);
  if (!aa || !bb) return false;
  if (aa === bb) return true;
  if (aa.length >= 8 && bb.includes(aa)) return true;
  if (bb.length >= 8 && aa.includes(bb)) return true;
  return false;
}

function productName(product) {
  return clean(product.nayax_product_name || product.internal_product_name || product.product_key);
}

function activeProductsForMachine(machineId) {
  return products.filter(p =>
    clean(p.machine_id || machineId) === clean(machineId) &&
    isActiveProduct(p)
  );
}

function getMdbCode(sale, parsed) {
  return firstNonEmpty(
    sale.mdb_code_extracted,
    sale.mdb_code,
    sale.MDBCode,
    sale.MdbCode,
    sale.MDB_CODE,
    sale.MDB,
    sale.ProductMDBCode,
    sale.ProductMdbCode,
    parsed.mdb_code
  );
}

function findProductByName(machineId, label, mdbCode) {
  const candidates = activeProductsForMachine(machineId)
    .filter(p => namesMatch(productName(p), label));

  if (!candidates.length) return null;

  const exactNorm = normalizeName(label);
  const exactCandidates = candidates.filter(p =>
    normalizeName(productName(p)) === exactNorm
  );

  const pool = exactCandidates.length ? exactCandidates : candidates;

  if (mdbCode) {
    const sameMdb = pool.find(p => clean(p.mdb_code) === clean(mdbCode));
    if (sameMdb) return sameMdb;
  }

  return pool[0];
}

function getProductForSale(sale) {
  const parsed = parseProductName(sale.ProductName);
  const machineId = clean(sale.MachineID || config.machine_id);
  const mdbCode = getMdbCode(sale, parsed);
  const product = findProductByName(machineId, parsed.label, mdbCode);

  if (!product) {
    return { product: null, parsed, mdbCode, expectedMdb: '', reason: 'UNKNOWN_PRODUCT' };
  }

  const expectedMdb = clean(product.mdb_code);

  if (!mdbCode) {
    return { product, parsed, mdbCode, expectedMdb, reason: 'MDB_CODE_MISSING_CONTROL' };
  }

  if (!expectedMdb) {
    return { product, parsed, mdbCode, expectedMdb, reason: 'MDB_EXPECTED_CODE_MISSING' };
  }

  if (expectedMdb !== mdbCode) {
    const productOnActualMdb = activeProductsForMachine(machineId)
      .find(p => clean(p.mdb_code) === mdbCode);

    const differentProductOnActualMdb =
      productOnActualMdb &&
      clean(productOnActualMdb.product_key) !== clean(product.product_key);

    return {
      product,
      parsed,
      mdbCode,
      expectedMdb,
      productOnActualMdb,
      reason: differentProductOnActualMdb
        ? 'MDB_PRODUCT_MAPPING_MISMATCH'
        : 'MDB_CODE_CHANGED_FOR_PRODUCT'
    };
  }

  return { product, parsed, mdbCode, expectedMdb, reason: 'OK' };
}

function getSoldQty(sale) {
  // Phase A2: Nayax API always returns Quantity=0 for individual sales.
  // Each transaction = 1 unit sold. Use default_quantity_per_sale (= 1).
  const multivendQty = Number(
    sale.MultivendNumverOfProducts ??
    sale.MultivendNumberOfProducts ??
    0
  );
  return multivendQty > 0
    ? multivendQty
    : Number(config.default_quantity_per_sale ?? 1);
}

function sortByMhd(a, b) {
  const aDate = clean(a.mhd) ? new Date(a.mhd) : new Date('9999-12-31');
  const bDate = clean(b.mhd) ? new Date(b.mhd) : new Date('9999-12-31');
  return aDate - bDate;
}

function productUpdateKey(product, machineId, mdbCode) {
  return clean(product.product_slot_id) ||
    [
      clean(machineId),
      clean(mdbCode || product.mdb_code),
      clean(product.product_key)
    ].join('|');
}

function queueProductQtyDeduction(product, machineId, mdbCode, soldQty) {
  const key = productUpdateKey(product, machineId, mdbCode);

  const currentQty = Number(
    String(product.current_machine_qty ?? '').replace(',', '.')
  );

  if (!Number.isFinite(currentQty)) {
    warnings.push({
      created_at: now,
      type: 'CURRENT_MACHINE_QTY_MISSING',
      severity: 'warning',
      machine_id: machineId,
      product_key: clean(product.product_key),
      nayax_product_name: productName(product),
      message: `current_machine_qty fehlt oder ist ungueltig fuer ${productName(product)}. Maschinenbestand wurde nicht aktualisiert.`,
      resolved: 'FALSE'
    });

    return;
  }

  const existing = productQtyUpdates.get(key);

  if (existing) {
    existing.deduct_qty += soldQty;

    existing.current_machine_qty = Math.max(
      0,
      currentQty - existing.deduct_qty
    );

    return;
  }

  productQtyUpdates.set(key, {
    product_slot_id: clean(product.product_slot_id),
    product_key: clean(product.product_key),
    machine_id: clean(machineId),
    mdb_code: clean(mdbCode || product.mdb_code),
    old_current_machine_qty: currentQty,
    deduct_qty: soldQty,
    current_machine_qty: Math.max(0, currentQty - soldQty),
    last_stock_update_at: now,
    last_stock_update_source: 'WF3_NAYAX_LAST_SALES',
    last_change_id: `WF3_SALE_${now}`,
    notes: `WF3: Maschinenbestand durch Verkauf reduziert. Alt=${currentQty}, Abzug=${soldQty}.`
  });
}

function addProductChangeSuggestionOnce(suggestion) {
  const key = [
    suggestion.change_type,
    suggestion.machine_id,
    suggestion.expected_mdb_code,
    suggestion.actual_mdb_code,
    suggestion.nayax_product_name,
    suggestion.existing_product_key,
    suggestion.suggested_product_key
  ].join('|');

  const exists = productChangeSuggestions.some(s => [
    s.change_type,
    s.machine_id,
    s.expected_mdb_code,
    s.actual_mdb_code,
    s.nayax_product_name,
    s.existing_product_key,
    s.suggested_product_key
  ].join('|') === key);

  if (!exists) productChangeSuggestions.push(suggestion);
}

function suggestedChangeTypeDe(reason) {
  if (reason === 'MDB_PRODUCT_MAPPING_MISMATCH') return 'Produkt im Slot austauschen';
  if (reason === 'MDB_CODE_CHANGED_FOR_PRODUCT') return 'Produkt auf anderen MDB-Slot umziehen';
  return '';
}

function addMdbWarning(sale, match) {
  if (![
    'MDB_CODE_CHANGED_FOR_PRODUCT',
    'MDB_PRODUCT_MAPPING_MISMATCH',
    'MDB_CODE_MISSING_CONTROL',
    'MDB_EXPECTED_CODE_MISSING'
  ].includes(match.reason)) return;

  const machineId = clean(sale.MachineID || config.machine_id);

  warnings.push({
    created_at: now,
    type: match.reason,
    severity: 'warning',
    machine_id: machineId,
    product_key: match.product ? clean(match.product.product_key) : '',
    nayax_product_name: clean(sale.ProductName),
    message: `MDB-Kontrolle fuer ${clean(sale.ProductName)}: erwartet ${match.expectedMdb || 'leer'}, Nayax meldet ${match.mdbCode || 'leer'}. Verkauf wird weiter verarbeitet.`,
    resolved: 'FALSE'
  });
}

function detectProductChangeSuggestion(sale, match) {
  const parsed = match.parsed || parseProductName(sale.ProductName);
  const machineId = clean(sale.MachineID || config.machine_id);
  const mdbCode = clean(match.mdbCode || getMdbCode(sale, parsed));

  if (!parsed.label || !mdbCode) return;

  if (match.product && [
    'MDB_CODE_CHANGED_FOR_PRODUCT',
    'MDB_PRODUCT_MAPPING_MISMATCH'
  ].includes(match.reason)) {
    const productOnActualMdb = match.productOnActualMdb ||
      activeProductsForMachine(machineId).find(p => clean(p.mdb_code) === mdbCode);

    const existingProduct = productOnActualMdb || match.product;
    const changeTypeDe = suggestedChangeTypeDe(match.reason);

    addProductChangeSuggestionOnce({
      created_at: now,
      source: 'WF3_NAYAX_LAST_SALES',
      detected_reason: match.reason,
      change_type: match.reason,
      machine_id: machineId,
      old_mdb_code: match.expectedMdb,
      new_mdb_code: mdbCode,
      expected_mdb_code: match.expectedMdb,
      actual_mdb_code: mdbCode,
      mdb_code: mdbCode,
      transaction_id: clean(sale.TransactionID),
      settlement_datetime_gmt: saleDatetime(sale),
      raw_product_name: clean(sale.ProductName),
      nayax_product_name: parsed.label,
      existing_product_key: clean(existingProduct.product_key),
      existing_nayax_product_name: productName(existingProduct),
      product_key: clean(match.product.product_key),
      suggested_product_key: clean(match.product.product_key),
      suggested_action: changeTypeDe,
      suggested_change_type: changeTypeDe,
      confidence: 'hoch',
      approved: 'FALSE',
      processed: 'FALSE',
      wf4_auto_start: 'TRUE',
      notes: match.reason === 'MDB_PRODUCT_MAPPING_MISMATCH'
        ? 'ProductName passt zu einem bekannten Produkt, aber der gemeldete MDB-Slot ist in Google Sheets einem anderen aktiven Produkt zugeordnet.'
        : 'ProductName passt zu einem bekannten Produkt, aber Nayax meldet einen anderen MDB-Code als Google Sheets.'
    });

    return;
  }

  if (!match.product) {
    const productOnActualMdb = activeProductsForMachine(machineId)
      .find(p => clean(p.mdb_code) === mdbCode);

    addProductChangeSuggestionOnce({
      created_at: now,
      source: 'WF3_NAYAX_LAST_SALES',
      detected_reason: productOnActualMdb ? 'PRODUCT_CHANGE' : 'NEW_PRODUCT',
      change_type: productOnActualMdb ? 'PRODUCT_CHANGE' : 'NEW_PRODUCT',
      machine_id: machineId,
      old_mdb_code: productOnActualMdb ? clean(productOnActualMdb.mdb_code) : '',
      new_mdb_code: mdbCode,
      expected_mdb_code: productOnActualMdb ? clean(productOnActualMdb.mdb_code) : '',
      actual_mdb_code: mdbCode,
      mdb_code: mdbCode,
      transaction_id: clean(sale.TransactionID),
      settlement_datetime_gmt: saleDatetime(sale),
      raw_product_name: clean(sale.ProductName),
      nayax_product_name: parsed.label,
      existing_product_key: productOnActualMdb ? clean(productOnActualMdb.product_key) : '',
      existing_nayax_product_name: productOnActualMdb ? productName(productOnActualMdb) : '',
      product_key: '',
      suggested_product_key: generateProductKey(parsed.label),
      suggested_action: productOnActualMdb
        ? 'Alte MDB-Zuordnung pruefen und neues Produkt erst im Stammdatenprozess anlegen'
        : 'Neues Produkt im Stammdatenprozess anlegen',
      suggested_change_type: 'Produkt im Slot austauschen',
      confidence: productOnActualMdb ? 'mittel' : 'pruefen',
      approved: 'FALSE',
      processed: 'FALSE',
      wf4_auto_start: 'FALSE',
      notes: productOnActualMdb
        ? 'Nayax-Produktname ist nicht bekannt, aber der MDB-Slot ist bereits einem anderen Produkt zugeordnet. WF4 wird nicht automatisch gestartet, weil das Zielprodukt noch nicht sicher existiert.'
        : 'Produktname wurde in den aktiven Produktstammdaten nicht gefunden. WF4 wird nicht automatisch gestartet, weil das Produkt erst angelegt werden muss.'
    });
  }
}

for (const batch of originalBatches) {
  const status = clean(batch.status).toLowerCase();
  if (status !== 'aktiv') continue;

  const remainingQty = Number(batch.remaining_qty);
  if (!Number.isFinite(remainingQty) || remainingQty <= 0) continue;

  if (!clean(batch.mhd)) {
    warnings.push({
      created_at: now,
      type: 'MHD_MISSING',
      severity: 'warning',
      machine_id: config.machine_id,
      product_key: batch.product_key,
      nayax_product_name: '',
      message: `Aktive Charge ${batch.batch_id} hat kein MHD.`,
      resolved: 'FALSE'
    });
    continue;
  }

  const mhdDate = new Date(batch.mhd);
  const daysLeft = Math.ceil((mhdDate - new Date()) / (1000 * 60 * 60 * 24));

  if (daysLeft < 0) {
    warnings.push({
      created_at: now,
      type: 'MHD_EXPIRED',
      severity: 'error',
      machine_id: config.machine_id,
      product_key: batch.product_key,
      nayax_product_name: '',
      message: `Charge ${batch.batch_id} ist abgelaufen. MHD: ${batch.mhd}.`,
      resolved: 'FALSE'
    });
  } else if (daysLeft <= warningDays) {
    warnings.push({
      created_at: now,
      type: 'MHD_WARNING',
      severity: 'warning',
      machine_id: config.machine_id,
      product_key: batch.product_key,
      nayax_product_name: '',
      message: `Charge ${batch.batch_id} laeuft in ${daysLeft} Tagen ab. MHD: ${batch.mhd}.`,
      resolved: 'FALSE'
    });
  }
}

for (const sale of sales) {
  const transactionId = clean(sale.TransactionID);
  const machineId = clean(sale.MachineID || config.machine_id);
  const rawProductName = clean(sale.ProductName);
  const sDate = saleDate(sale);

  if (!transactionId) {
    warnings.push({
      created_at: now,
      type: 'MISSING_TRANSACTION_ID',
      severity: 'error',
      machine_id: machineId,
      product_key: '',
      nayax_product_name: rawProductName,
      message: 'Verkauf ohne TransactionID erhalten. Nicht verarbeitet.',
      resolved: 'FALSE'
    });
    continue;
  }

  if (sDate <= lastSuccessfulSaleDate) continue;
  if (sDate < cutoverDate) continue;
  if (processed.has(transactionId)) continue;

  processed.add(transactionId);

  // Phase A2: Filter zero-value transactions (Prepaid Credits, Stornos, Testtransaktionen).
  // SettlementValue=0 bedeutet kein echter Produktverkauf. Kein Log, keine FIFO-Abbuchung.
  const settlementValue = Number(sale.SettlementValue);
  if (!Number.isFinite(settlementValue) || settlementValue <= 0) {
    if (sDate > maxProcessedSaleDate) maxProcessedSaleDate = sDate;
    continue;
  }
  const vkPreisBrutto = settlementValue;

  // Phase A2: mdb_code_extracted already enriched by 'Code in JavaScript' node
  const mdbExtracted = clean(sale.mdb_code_extracted || '');

  if (!rawProductName) {
    transactionLogs.push({
      transaction_id: transactionId,
      machine_id: machineId,
      nayax_product_name: '',
      product_key: '',
      quantity: getSoldQty(sale),
      settlement_datetime_gmt: saleDatetime(sale),
      processed_at: now,
      status: 'MISSING_PRODUCT_NAME',
      notes: 'Transaktion ohne Produktname erhalten. Nicht abgebucht.',
      vk_preis_brutto: vkPreisBrutto,
      umsatz_brutto: 0,
      mdb_code_extracted: mdbExtracted,
      batch_id_abgebucht: ''
    });

    warnings.push({
      created_at: now,
      type: 'MISSING_PRODUCT_NAME',
      severity: 'error',
      machine_id: machineId,
      product_key: '',
      nayax_product_name: '',
      message: `Transaktion ${transactionId} enthaelt keinen Produktnamen.`,
      resolved: 'FALSE'
    });

    if (sDate > maxProcessedSaleDate) maxProcessedSaleDate = sDate;
    continue;
  }

  const match = getProductForSale(sale);
  detectProductChangeSuggestion(sale, match);

  const { product, mdbCode, expectedMdb, reason } = match;
  const soldQty = getSoldQty(sale);

  if (!product) {
    transactionLogs.push({
      transaction_id: transactionId,
      machine_id: machineId,
      nayax_product_name: rawProductName,
      product_key: '',
      quantity: soldQty,
      settlement_datetime_gmt: saleDatetime(sale),
      processed_at: now,
      status: reason,
      notes: `Keine gueltige Produktzuordnung ueber ProductName gefunden. MDB: ${mdbCode || 'leer'}`,
      vk_preis_brutto: vkPreisBrutto,
      umsatz_brutto: 0,
      mdb_code_extracted: mdbExtracted,
      batch_id_abgebucht: ''
    });

    warnings.push({
      created_at: now,
      type: reason,
      severity: 'error',
      machine_id: machineId,
      product_key: '',
      nayax_product_name: rawProductName,
      message: `Keine gueltige Produktzuordnung ueber ProductName gefunden. MDB: ${mdbCode || 'leer'}`,
      resolved: 'FALSE'
    });

    if (sDate > maxProcessedSaleDate) maxProcessedSaleDate = sDate;
    continue;
  }

  addMdbWarning(sale, match);

  let remainingToDeduct = soldQty;

  const productBatches = [...batchMap.values()]
    .filter(b =>
      clean(b.product_key) === clean(product.product_key) &&
      clean(b.status).toLowerCase() === 'aktiv' &&
      Number(b.remaining_qty) > 0
    )
    .sort(sortByMhd);

  // Phase A2: Track which batch IDs were actually deducted
  const deductedBatches = [];

  for (const batch of productBatches) {
    if (remainingToDeduct <= 0) break;

    const available = Number(batch.remaining_qty);
    const deduct = Math.min(available, remainingToDeduct);

    batch.remaining_qty = available - deduct;
    remainingToDeduct -= deduct;

    if (batch.remaining_qty <= 0) batch.status = 'leer';

    batchMap.set(String(batch.batch_id), batch);
    deductedBatches.push(String(batch.batch_id));
  }

  const transactionStatus = remainingToDeduct > 0
    ? 'INSUFFICIENT_BATCH_STOCK'
    : 'OK';

  const mdbNote = reason === 'OK'
    ? `MDB ${mdbCode || 'leer'} bestaetigt.`
    : `MDB-Kontrolle ${reason}: erwartet ${expectedMdb || 'leer'}, Nayax meldet ${mdbCode || 'leer'}.`;

  transactionLogs.push({
    transaction_id: transactionId,
    machine_id: machineId,
    nayax_product_name: rawProductName,
    product_key: product.product_key,
    quantity: soldQty,
    settlement_datetime_gmt: saleDatetime(sale),
    processed_at: now,
    status: transactionStatus,
    notes: remainingToDeduct > 0
      ? `Nicht genug aktiver Lagerbestand. Fehlmenge: ${remainingToDeduct}. ${mdbNote}`
      : `Abgebucht ueber product_key ${product.product_key}. ${mdbNote}`,
    vk_preis_brutto: vkPreisBrutto,
    umsatz_brutto: soldQty * vkPreisBrutto,
    mdb_code_extracted: mdbExtracted,
    batch_id_abgebucht: deductedBatches.join(', ')
  });

  if (transactionStatus === 'OK') {
    queueProductQtyDeduction(product, machineId, mdbCode, soldQty);
  }

  if (remainingToDeduct > 0) {
    warnings.push({
      created_at: now,
      type: 'INSUFFICIENT_BATCH_STOCK',
      severity: 'error',
      machine_id: machineId,
      product_key: product.product_key,
      nayax_product_name: rawProductName,
      message: `Nicht genug aktiver Lagerbestand. Fehlmenge: ${remainingToDeduct}`,
      resolved: 'FALSE'
    });
  }

  if (sDate > maxProcessedSaleDate) {
    maxProcessedSaleDate = sDate;
  }
}

const updatedBatches = [...batchMap.values()].filter(newBatch => {
  const oldBatch = originalBatches.find(b =>
    String(b.batch_id) === String(newBatch.batch_id)
  );

  return oldBatch &&
    (
      String(oldBatch.remaining_qty) !== String(newBatch.remaining_qty) ||
      String(oldBatch.status) !== String(newBatch.status)
    );
});

return [{
  json: {
    updatedBatches,
    transactionLogs,
    warnings,
    productChangeSuggestions,
    productQtyUpdates: [...productQtyUpdates.values()],
    summary: {
      sales_received: sales.length,
      processed_transaction_logs: transactionLogs.length,
      batch_updates: updatedBatches.length,
      warnings: warnings.length,
      product_change_suggestions: productChangeSuggestions.length,
      product_qty_updates: productQtyUpdates.size,
      wf4_auto_start_candidates: productChangeSuggestions
        .filter(s => clean(s.wf4_auto_start).toUpperCase() === 'TRUE')
        .length,
      processed_at: now,
      previous_last_inventory_review_at: lastSuccessfulSaleDate.toISOString(),
      last_successful_sale_datetime_gmt: maxProcessedSaleDate.toISOString(),
      should_update_watermark: maxProcessedSaleDate > lastSuccessfulSaleDate
    }
  }
}];

function clean(value) {
  return String(value ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

function firstNonEmpty(...values) {
  return values.map(clean).find(value => value !== '') || '';
}

function parseProductName(raw) {
  const text = clean(raw);
  const match = text.match(/^(.*?)\s*\((\d+)\s*=\s*([0-9]+(?:[.,][0-9]+)?)\s*\)/);
  return {
    label: match ? clean(match[1]) : text,
    mdb_code: match ? String(match[2]) : '',
    sale_price_eur: match ? String(match[3]).replace(',', '.') : ''
  };
}

return $input.all().map(item => {
  const productName = clean(item.json.ProductName || item.json.product_name || item.json.nayax_product_name);
  const parsed = parseProductName(productName);
  const explicitMdb = firstNonEmpty(
    item.json.mdb_code,
    item.json.MDBCode,
    item.json.MdbCode,
    item.json.MDB_CODE,
    item.json.MDB,
    item.json.ProductMDBCode,
    item.json.ProductMdbCode,
    item.json.SlotNumber,
    item.json.SlotId
  );

  return {
    json: {
      ...item.json,
      ProductName: productName || item.json.ProductName,
      nayax_product_label: parsed.label,
      mdb_code_extracted: firstNonEmpty(explicitMdb, parsed.mdb_code),
      sale_price_eur_extracted: parsed.sale_price_eur
    }
  };
});

function clean(value) {
  return String(value ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

const defaultChangeType = {
  MDB_CODE_CHANGED_FOR_PRODUCT: 'Produkt auf anderen MDB-Slot umziehen',
  MDB_PRODUCT_MAPPING_MISMATCH: 'Produkt im Slot austauschen'
};

return $input.all()
  .map(item => item.json)
  .filter(row => clean(row.wf4_auto_start).toUpperCase() === 'TRUE')
  .map(row => ({
    json: {
      source: 'WF3_NAYAX_LAST_SALES',
      detected_reason: clean(row.detected_reason || row.change_type),
      machine_id: clean(row.machine_id),
      nayax_product_name: clean(row.raw_product_name || row.nayax_product_name),
      raw_product_name: clean(row.raw_product_name || row.nayax_product_name),
      product_label: clean(row.nayax_product_name),
      expected_mdb_code: clean(row.expected_mdb_code || row.old_mdb_code),
      actual_mdb_code: clean(row.actual_mdb_code || row.new_mdb_code || row.mdb_code),
      old_mdb_code: clean(row.expected_mdb_code || row.old_mdb_code),
      new_mdb_code: clean(row.actual_mdb_code || row.new_mdb_code || row.mdb_code),
      product_key: clean(row.suggested_product_key || row.product_key),
      suggested_product_key: clean(row.suggested_product_key || row.product_key),
      settlement_datetime_gmt: clean(row.settlement_datetime_gmt),
      sale_datetime_utc: clean(row.settlement_datetime_gmt),
      transaction_id: clean(row.transaction_id),
      suggested_change_type: clean(row.suggested_change_type || defaultChangeType[row.detected_reason || row.change_type]),
      notes: clean(row.notes)
    }
  }));

const summary = $input.first().json.summary || {};

if (!summary.should_update_watermark) {
  return [];
}

return [{
  json: {
    workflow_key: 'WF3_NAYAX_FIFO',
    last_inventory_review_at: summary.last_successful_sale_datetime_gmt
  }
}];

const data = $input.first().json.productQtyUpdates || [];

return data.map(row => ({
  json: row
}));
